using UnityEngine;

/// <summary>
/// Objectivo cumprido quando uma variável global bool (GameVariables) tem o
/// valor "expectedValue". Genérico — cobre "chegar a uma zona/checkpoint"
/// (uma zona/gatilho na cena usa Action_SetBoolVariable ao entrar), "puzzle
/// resolvido", "NPC salvo/encontrado", etc., reaproveitando o mesmo mecanismo
/// de Condition_BoolVariable/Action_SetBoolVariable já usado pelos NPCs —
/// sem precisar de nenhum script novo por desafio.
///
/// Objectivo binário (sem contador) — <see cref="TargetProgress"/> devolve -1.
/// </summary>
[System.Serializable]
public class Objective_BoolVariable : ChallengeObjective
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como tendo o valor por omissão (false).")]
    public string variableName;

    [Tooltip("Valor que a variável tem de ter para este objectivo estar cumprido.")]
    public bool expectedValue = true;

    public override bool IsComplete()
    {
        bool actual = GameVariables.Instance != null && GameVariables.Instance.GetBool(variableName);
        return actual == expectedValue;
    }
}

/// <summary>
/// Objectivo cumprido quando uma variável global int (GameVariables) cumpre
/// "comparison" face a "targetValue". Genérico — cobre contadores mantidos por
/// Action_IncrementIntVariable/Action_SetIntVariable já existentes: derrotar N
/// inimigos, recolher N objectos, ondas sobrevividas, etc.
///
/// Mostra "actual/targetValue" no HUD (Tarefa #12).
/// </summary>
[System.Serializable]
public class Objective_IntVariableThreshold : ChallengeObjective
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como tendo o valor por omissão (0).")]
    public string variableName;

    [Tooltip("Como comparar o valor actual da variável com \"targetValue\".")]
    public Comparison comparison = Comparison.GreaterOrEqual;

    [Tooltip("Valor-alvo, mostrado no HUD como \"actual/targetValue\".")]
    public int targetValue;

    public override bool IsComplete()
    {
        int actual = GameVariables.Instance != null ? GameVariables.Instance.GetInt(variableName) : 0;
        return NpcConditionUtil.Compare(actual, comparison, targetValue);
    }

    public override int CurrentProgress() => GameVariables.Instance != null ? GameVariables.Instance.GetInt(variableName) : 0;

    public override int TargetProgress() => targetValue;
}
